import { Component, OnInit } from '@angular/core';
import { NavigationEnd, Router } from '@angular/router';
import { filter } from 'rxjs/operators';
import { AuthService } from '../../core/services/auth.service';

@Component({
  selector: 'app-main-layout',
  templateUrl: './main-layout.component.html'
})
export class MainLayoutComponent implements OnInit {
  builderWorkspace = false;
  publicLanding = false;

  constructor(
    private readonly authService: AuthService,
    private readonly router: Router
  ) {
  }

  ngOnInit(): void {
    this.authService.hydrateUser();
    this.syncWorkspaceMode(this.router.url);
    this.router.events.pipe(
      filter((event): event is NavigationEnd => event instanceof NavigationEnd)
    ).subscribe((event) => {
      this.syncWorkspaceMode(event.urlAfterRedirects);
    });
  }

  private syncWorkspaceMode(url: string): void {
    this.builderWorkspace = [
      '/resume-builder/create/',
      '/resume-builder/edit/',
      '/resume-builder/preview/'
    ].some((prefix) => url.startsWith(prefix));

    this.publicLanding = !this.authService.isAuthenticated() && (url === '/dashboard' || url === '/');
  }
}
<div *ngIf="builderWorkspace; else standardLayout" class="min-h-screen bg-[#f3efe7] px-3 py-3 md:px-4">
  <div class="mx-auto max-w-[1600px]">
    <router-outlet></router-outlet>
  </div>
</div>

<ng-template #standardLayout>
  <div *ngIf="publicLanding; else appLayout" class="min-h-screen bg-[#f8f3ec]">
    <router-outlet></router-outlet>
  </div>

  <ng-template #appLayout>
  <div class="min-h-screen px-4 py-4 md:px-6">
    <div class="mx-auto grid min-h-[calc(100vh-2rem)] max-w-7xl gap-4 lg:grid-cols-[280px_1fr]">
      <app-sidebar></app-sidebar>

      <main class="space-y-4">
        <app-navbar></app-navbar>
        <section class="glass-panel min-h-[calc(100vh-9rem)] p-4 md:p-6">
          <router-outlet></router-outlet>
        </section>
      </main>
    </div>
  </div>
  </ng-template>
</ng-template>
